import { TextStyleContext } from '@/registry/components/ui/text';
import * as React from 'react';
import {
    Pressable,
    StyleSheet,
    View,
    type PressableProps,
    type StyleProp,
    type TextStyle,
    type ViewStyle,
} from 'react-native';

type ButtonVariant = 'default' | 'destructive' | 'outline' | 'secondary' | 'ghost' | 'link';
type ButtonSize = 'default' | 'sm' | 'lg' | 'icon';

type ButtonProps = Omit<PressableProps, 'children'> &
    {
        children?: React.ReactNode;
        className?: string;
        variant?: ButtonVariant;
        size?: ButtonSize;
    };

function getButtonStyle(variant: ButtonVariant): StyleProp<ViewStyle> {
    switch (variant) {
        case 'destructive':
            return styles.destructiveButton;
        case 'outline':
            return styles.outlineButton;
        case 'secondary':
            return styles.secondaryButton;
        case 'ghost':
            return styles.ghostButton;
        case 'link':
            return styles.linkButton;
        default:
            return styles.defaultButton;
    }
}

function getButtonTextStyle(variant: ButtonVariant): StyleProp<TextStyle> {
    switch (variant) {
        case 'destructive':
            return styles.destructiveText;
        case 'outline':
            return styles.outlineText;
        case 'secondary':
            return styles.secondaryText;
        case 'ghost':
            return styles.ghostText;
        case 'link':
            return styles.linkText;
        default:
            return styles.defaultText;
    }
}

function getSizeStyle(size: ButtonSize): StyleProp<ViewStyle> {
    switch (size) {
        case 'sm':
            return styles.smButton;
        case 'lg':
            return styles.lgButton;
        case 'icon':
            return styles.iconButton;
        default:
            return styles.mdButton;
    }
}

function Button({ style, variant = 'default', size = 'default', disabled, children, ...props }: ButtonProps) {
    const resolvedStyle = style as StyleProp<ViewStyle>;

    return (
        <Pressable disabled={disabled} role="button" style={resolvedStyle} {...props}>
            {({ pressed }) => (
                <TextStyleContext.Provider value={[styles.buttonTextBase, getButtonTextStyle(variant)]}>
                    <View
                        style={[
                            styles.baseButton,
                            getButtonStyle(variant),
                            getSizeStyle(size),
                            pressed && variant !== 'link' ? styles.pressed : undefined,
                            disabled ? styles.disabled : undefined,
                        ]}
                    >
                        {children}
                    </View>
                </TextStyleContext.Provider>
            )}
        </Pressable>
    );
}

const styles = StyleSheet.create({
    baseButton: {
        alignItems: 'center',
        borderRadius: 8,
        flexDirection: 'row',
        gap: 8,
        justifyContent: 'center',
    },
    defaultButton: {
        backgroundColor: '#18181b',
    },
    destructiveButton: {
        backgroundColor: '#ef4444',
    },
    outlineButton: {
        backgroundColor: '#ffffff',
        borderColor: '#e4e4e7',
        borderWidth: 1,
    },
    secondaryButton: {
        backgroundColor: '#f4f4f5',
    },
    ghostButton: {
        backgroundColor: 'transparent',
    },
    linkButton: {
        backgroundColor: 'transparent',
        paddingHorizontal: 0,
        paddingVertical: 0,
    },
    mdButton: {
        minHeight: 40,
        paddingHorizontal: 16,
        paddingVertical: 10,
    },
    smButton: {
        minHeight: 36,
        paddingHorizontal: 12,
        paddingVertical: 8,
    },
    lgButton: {
        minHeight: 44,
        paddingHorizontal: 24,
        paddingVertical: 12,
    },
    iconButton: {
        height: 40,
        justifyContent: 'center',
        paddingHorizontal: 0,
        width: 40,
    },
    pressed: {
        opacity: 0.9,
    },
    disabled: {
        opacity: 0.5,
    },
    buttonTextBase: {
        fontSize: 14,
        fontWeight: '600',
    },
    defaultText: {
        color: '#fafafa',
    },
    destructiveText: {
        color: '#fafafa',
    },
    outlineText: {
        color: '#18181b',
    },
    secondaryText: {
        color: '#18181b',
    },
    ghostText: {
        color: '#18181b',
    },
    linkText: {
        color: '#18181b',
        textDecorationLine: 'underline',
    },
});

export { Button };
export type { ButtonProps };

import * as Slot from '@rn-primitives/slot';
import * as React from 'react';
import {
    Platform,
    StyleSheet,
    Text as RNText,
    type Role,
    type StyleProp,
    type TextStyle,
} from 'react-native';

type TextVariant =
    | 'default'
    | 'h1'
    | 'h2'
    | 'h3'
    | 'h4'
    | 'p'
    | 'blockquote'
    | 'code'
    | 'lead'
    | 'large'
    | 'small'
    | 'muted';

type TextProps = React.ComponentProps<typeof RNText> &
    React.RefAttributes<RNText> & {
        asChild?: boolean;
        className?: string;
        variant?: TextVariant;
    };

const ROLE: Partial<Record<TextVariant, Role>> = {
    h1: 'heading',
    h2: 'heading',
    h3: 'heading',
    h4: 'heading',
    blockquote: Platform.select({ web: 'blockquote' as Role }),
    code: Platform.select({ web: 'code' as Role }),
};

const ARIA_LEVEL: Partial<Record<TextVariant, string>> = {
    h1: '1',
    h2: '2',
    h3: '3',
    h4: '4',
};

const TextStyleContext = React.createContext<StyleProp<TextStyle> | undefined>(undefined);

function getVariantStyle(variant: TextVariant): StyleProp<TextStyle> {
    switch (variant) {
        case 'h1':
            return styles.h1;
        case 'h2':
            return styles.h2;
        case 'h3':
            return styles.h3;
        case 'h4':
            return styles.h4;
        case 'p':
            return styles.p;
        case 'blockquote':
            return styles.blockquote;
        case 'code':
            return styles.code;
        case 'lead':
            return styles.lead;
        case 'large':
            return styles.large;
        case 'small':
            return styles.small;
        case 'muted':
            return styles.muted;
        default:
            return styles.default;
    }
}

function Text({ style, asChild = false, variant = 'default', ...props }: TextProps) {
    const inheritedStyle = React.useContext(TextStyleContext);
    const Component = asChild ? Slot.Text : RNText;

    return (
        <Component
            style={[styles.base, getVariantStyle(variant), inheritedStyle, style]}
            role={ROLE[variant]}
            aria-level={ARIA_LEVEL[variant]}
            {...props}
        />
    );
}

const styles = StyleSheet.create({
    base: {
        color: '#09090b',
        fontSize: 16,
    },
    default: {},
    h1: {
        fontSize: 36,
        fontWeight: '800',
        lineHeight: 40,
    },
    h2: {
        fontSize: 30,
        fontWeight: '700',
        lineHeight: 34,
        paddingBottom: 8,
        borderBottomWidth: StyleSheet.hairlineWidth,
        borderBottomColor: '#e4e4e7',
    },
    h3: {
        fontSize: 24,
        fontWeight: '700',
        lineHeight: 28,
    },
    h4: {
        fontSize: 20,
        fontWeight: '600',
        lineHeight: 24,
    },
    p: {
        lineHeight: 24,
    },
    blockquote: {
        borderLeftWidth: 3,
        borderLeftColor: '#e4e4e7',
        fontStyle: 'italic',
        paddingLeft: 12,
    },
    code: {
        backgroundColor: '#f4f4f5',
        borderRadius: 6,
        fontFamily: Platform.select({ ios: 'Menlo', android: 'monospace', default: 'monospace' }),
        fontSize: 13,
        fontWeight: '600',
        overflow: 'hidden',
        paddingHorizontal: 6,
        paddingVertical: 4,
    },
    lead: {
        color: '#71717a',
        fontSize: 20,
        lineHeight: 28,
    },
    large: {
        fontSize: 18,
        fontWeight: '600',
        lineHeight: 24,
    },
    small: {
        fontSize: 14,
        fontWeight: '500',
    },
    muted: {
        color: '#71717a',
        fontSize: 14,
        lineHeight: 20,
    },
});

export { Text, TextStyleContext };

import * as React from 'react';
import { StyleSheet, TextInput, type TextInputProps } from 'react-native';

type InputProps = TextInputProps & {
    className?: string;
    variant?: 'default' | 'ghost';
};

function Input({ style, variant = 'default', editable = true, ...props }: InputProps) {
    return (
        <TextInput
            style={[
                styles.base,
                variant === 'ghost' ? styles.ghost : styles.default,
                editable === false ? styles.disabled : undefined,
                style,
            ]}
            editable={editable}
            placeholderTextColor="#71717a"
            {...props}
        />
    );
}

const styles = StyleSheet.create({
    base: {
        borderRadius: 8,
        color: '#09090b',
        fontSize: 14,
        minHeight: 40,
        paddingHorizontal: 12,
        paddingVertical: 10,
        width: '100%',
    },
    default: {
        backgroundColor: '#ffffff',
        borderColor: '#e4e4e7',
        borderWidth: 1,
    },
    ghost: {
        backgroundColor: '#f4f4f5',
        borderColor: 'transparent',
        borderWidth: 1,
    },
    disabled: {
        opacity: 0.5,
    },
});

export { Input };
export type { InputProps };

import { TextStyleContext } from '@/registry/components/ui/text';
import * as React from 'react';
import { StyleSheet, View, type ViewProps } from 'react-native';

type BadgeVariant = 'default' | 'secondary' | 'destructive' | 'outline';

type BadgeProps = ViewProps & {
    className?: string;
    variant?: BadgeVariant;
};

function Badge({ style, variant = 'default', children, ...props }: BadgeProps) {
    return (
        <TextStyleContext.Provider value={[styles.textBase, getTextStyle(variant)]}>
            <View style={[styles.base, getContainerStyle(variant), style]} {...props}>
                {children}
            </View>
        </TextStyleContext.Provider>
    );
}

function getContainerStyle(variant: BadgeVariant) {
    switch (variant) {
        case 'secondary':
            return styles.secondary;
        case 'destructive':
            return styles.destructive;
        case 'outline':
            return styles.outline;
        default:
            return styles.default;
    }
}

function getTextStyle(variant: BadgeVariant) {
    switch (variant) {
        case 'secondary':
            return styles.secondaryText;
        case 'destructive':
            return styles.destructiveText;
        case 'outline':
            return styles.outlineText;
        default:
            return styles.defaultText;
    }
}

const styles = StyleSheet.create({
    base: {
        alignItems: 'center',
        borderRadius: 999,
        flexDirection: 'row',
        paddingHorizontal: 10,
        paddingVertical: 4,
    },
    default: {
        backgroundColor: '#18181b',
        borderColor: 'transparent',
        borderWidth: 1,
    },
    secondary: {
        backgroundColor: '#f4f4f5',
        borderColor: 'transparent',
        borderWidth: 1,
    },
    destructive: {
        backgroundColor: '#ef4444',
        borderColor: 'transparent',
        borderWidth: 1,
    },
    outline: {
        backgroundColor: '#ffffff',
        borderColor: '#e4e4e7',
        borderWidth: 1,
    },
    textBase: {
        fontSize: 12,
        fontWeight: '600',
    },
    defaultText: {
        color: '#fafafa',
    },
    secondaryText: {
        color: '#18181b',
    },
    destructiveText: {
        color: '#fafafa',
    },
    outlineText: {
        color: '#18181b',
    },
});

export { Badge };
export type { BadgeProps };

import * as React from 'react';
import { Image, StyleSheet, View, type ImageProps, type ViewProps } from 'react-native';

type AvatarProps = ViewProps & {
    alt?: string;
    className?: string;
};

type AvatarImageProps = ImageProps & {
    className?: string;
    src?: string;
};

type AvatarFallbackProps = ViewProps & {
    className?: string;
};

function getSizeStyle(className?: string) {
    if (!className) return undefined;
    if (className.includes('h-20') || className.includes('w-20')) return styles.size20;
    if (className.includes('h-16') || className.includes('w-16')) return styles.size16;
    if (className.includes('h-14') || className.includes('w-14')) return styles.size14;
    return undefined;
}

function Avatar({ className, style, ...props }: AvatarProps) {
    return <View style={[styles.base, getSizeStyle(className), style]} {...props} />;
}

function AvatarImage({ style, src, source, ...props }: AvatarImageProps) {
    return <Image style={[styles.image, style]} source={source ?? (src ? { uri: src } : undefined)} {...props} />;
}

function AvatarFallback({ style, ...props }: AvatarFallbackProps) {
    return <View style={[styles.fallback, style]} {...props} />;
}

const styles = StyleSheet.create({
    base: {
        borderRadius: 999,
        height: 40,
        overflow: 'hidden',
        width: 40,
    },
    image: {
        height: '100%',
        width: '100%',
    },
    fallback: {
        alignItems: 'center',
        backgroundColor: '#f4f4f5',
        flex: 1,
        justifyContent: 'center',
    },
    size14: {
        height: 56,
        width: 56,
    },
    size16: {
        height: 64,
        width: 64,
    },
    size20: {
        height: 80,
        width: 80,
    },
});

export { Avatar, AvatarFallback, AvatarImage };
export type { AvatarFallbackProps, AvatarImageProps, AvatarProps };

